const allItems = $input.all();
let frequency = ""

let reportType = "General";
try { 
    reportType = $("Credentials Loop").first().json["type"] || "General"; 
} catch(e) {}

// Si no hay ítems de entrada, validamos anti-spam básico
if (allItems.length === 0) {
    if (['Bi-hourly', 'Hourly'].includes(reportType)) return []; 
    return { json: { htmlContent: "<p>No hay datos que procesar.</p>" } };
}

const allQueries = allItems.map(item => item.json);
let validHtmlParts = []; 
let hiddenQueriesCount = 0;

// --- 1. ESTILOS MÍNIMOS (Centralizados para evitar repetición) ---
