// [NODO: FAN IN - AGREGADOR]
// MODO: Run Once for All Items

const groupedItems = new Map();
const finalOutput = [];

const hasData = (sqlResultData) => {
  if (!sqlResultData || !Array.isArray(sqlResultData) || sqlResultData.length === 0) return false;
  return sqlResultData.some(row => (row && Object.keys(row).length > 0));
};

for (const item of items) {
  const json = item.json;
  const parentId = json.parentGroupId;

  // --- CASO 1: ITEM NORMAL ---
  if (!parentId) {
    finalOutput.push(item);
    continue;
  }

  // --- CASO 2: ITEM PARTICIONADO ---
  if (hasData(json.result)) {
    if (!groupedItems.has(parentId)) {
      const baseItem = JSON.parse(JSON.stringify(item));
      if (baseItem.json.associatedCorrection) {
         baseItem.json.correctionQuery = baseItem.json.associatedCorrection;
      }
      baseItem.json.revisionQuery = (baseItem.json.revisionQuery || '').trim();
      baseItem.json.correctionQuery = (baseItem.json.correctionQuery || '').trim();
      groupedItems.set(parentId, baseItem);
    } else {
      const groupItem = groupedItems.get(parentId);
      const currentJson = json;
      groupItem.json.result.push(...currentJson.result);

      if (currentJson.revisionQuery) {
        groupItem.json.revisionQuery += '\n\n' + currentJson.revisionQuery.trim();
      }
      const currentCorrection = currentJson.associatedCorrection || currentJson.correctionQuery;
      if (currentCorrection) {
        const prevCorrection = groupItem.json.correctionQuery;
        groupItem.json.correctionQuery = prevCorrection 
          ? prevCorrection + '\n\n' + currentCorrection.trim() 
          : currentCorrection.trim();
      }
    }
  }
}

// Volcamos los grupos al array final
for (const groupItem of groupedItems.values()) {
  const json = groupItem.json;
  delete json.parentGroupId;
  delete json.subQueryIndex;
  delete json.queryType;
  delete json.associatedCorrection;
  groupItem.json = json;
  finalOutput.push(groupItem);
}

// CORRECCIÓN DE ORDEN: Ordenamos por queryId (ej: 1.2, 1.3, 1.4)
// Asumimos que queryId es un string como "1.2", "1.3", "4.9". 
// Usamos localeCompare con 'numeric: true' para que ordene bien números (2 vs 10).
finalOutput.sort((a, b) => {
    const idA = String(a.json.queryId || '');
    const idB = String(b.json.queryId || '');
    return idA.localeCompare(idB, undefined, { numeric: true, sensitivity: 'base' });
});

return finalOutput;

const endTime = new Date().getTime();
const firstInput = $input.first().json;

// 1. Tiempo de inicio
const startTime = $('Audit Start').first().json.audit_startTime;
const envData   = $('Credentials Loop').item.json;
const queryData = $('Query Loop').item.json;

// 2. Detectar error y estado
const hasError = firstInput.error !== undefined && firstInput.error !== null;
const errorMessage = firstInput.error_message || null;

// 3. Peso y conteo (solo si no hay error)
let payloadString, sizeInBytes, realResultsCount;
if (hasError) {
  payloadString = errorMessage || 'Error en ejecución';
  sizeInBytes = Buffer.byteLength(payloadString, 'utf8');
  realResultsCount = 0;
} else {
  const results = $input.all();
  payloadString = JSON.stringify(results);
  sizeInBytes = Buffer.byteLength(payloadString, 'utf8');
  realResultsCount = (results.length === 1 && Object.keys(results[0].json).length === 0) ? 0 : results.length;
}

// 4. Fechas y timestamps
const now = new Date();
const arDateStr = now.toLocaleDateString("en-CA", { timeZone: "America/Argentina/Buenos_Aires" });
const arTimeStr = now.toLocaleTimeString("en-GB", { timeZone: "America/Argentina/Buenos_Aires" });
const isoNow = now.toISOString();
const timestamp_tz_normalizado = isoNow.replace('T', ' ').split('.')[0] + '+00';

return [{
  json: {
    query:             queryData.queryId       || 'N/A',
    pais:              envData.country          || 'Desconocido',
    entorno:           envData.entorno          || 'Desconocido',
    frecuencia:        queryData.type           || 'N/A',
    description:       queryData.description    || 'Sin descripción',
    aplicacion:        queryData.application     || 'N/A',
    tiempo:            parseFloat(((endTime - startTime) / 1000).toFixed(2)),
    peso:              parseFloat((sizeInBytes / 1024).toFixed(2)),
    filas_encontradas: realResultsCount,
    timestamp_tz:      timestamp_tz_normalizado,
    fecha_real:        arDateStr,
    hora_limpia:       arTimeStr,
    status:            hasError ? false : true,
    error_message:     errorMessage
  }
}];

const items = $input.all();

for (const item of items) {
  // 1. Obtenemos el timezone que definimos en las credenciales
  const zone = $node["Credentials Loop"].json.timezone; 

  // 2. Calculamos la hora fresca
  // Importante: DateTime es global en n8n
  item.json.hora_ejecucion_real = DateTime.now()
    .setZone(zone)
    .toFormat("yyyy-MM-dd'T'HH:mm:ss.SSS");

  // Timestamp para auditoría (milisegundos)
  item.json.audit_startTime = new Date().getTime();
  item.json.timeout = "10000"
}

return items;

// Classify SQL Execute error as TRANSIENT or FATAL.
const TRANSIENT_PATTERNS = [
  /timeout/i, /deadlock/i, /session.*kill/i, /killed.*session/i,
  /connection.*reset/i, /connection.*lost/i, /network.*error/i,
  /etimedout/i, /econnrefused/i, /econnreset/i
];
const FATAL_PATTERNS = [
  /login failed/i, /authentication/i, /password/i,
  /invalid object name/i, /syntax error/i, /permission denied/i,
  /access.*denied/i, /must declare the scalar variable/i, /must be/i
];

const items = $input.all();
return items.map(item => {
  const rawError = item.json.error || item.error?.message || JSON.stringify(item.json);
  const msg = String(rawError);
  let errorType = 'TRANSIENT';
