  const rawError = item.json.error || item.error?.message || JSON.stringify(item.json);
  const msg = String(rawError);
  let errorType = 'TRANSIENT';
  if (FATAL_PATTERNS.some(re => re.test(msg))) errorType = 'FATAL';
  else if (!TRANSIENT_PATTERNS.some(re => re.test(msg))) errorType = 'TRANSIENT';
  return { json: { ...item.json, error_type: errorType, error_message: msg.slice(0, 1000), timeout: "180000" } };
});
